onClick:
{{
  (() => {
// 1. Sinaliza atividade para o sistema de segurança (reseta os 15 min)
 JSutils.resetInactivityTimer();		
// 2 - Definimos os dados que vêm dos inputs do seu formulário/container
const formData = {
    acomo002_id: InputID.text, 
    acomo002_desc: InputDescricao.text?.trim().toUpperCase(),
    // Garantimos que valores numéricos vazios virem 0
acomo002_valor_base: Number(CurrencyInput1Valor.value) || 0, 
    acomo002_limite_pets: Number(InputQtdade.text) || 0,
    acomo002_permite_especie: Select1Tipo.selectedOptionValue,
};

    if (appsmith.store.modalContexto?.acaoTipo === "ADICIONAR") {
      return JSconfirmation.showModal({
        action: "Insert",
        message: "Deseja salvar este novo registro?",
        icon: "plus",
        color: "green",
				row: formData
      });
    } else {
      return JSconfirmation.showModal({
        action: "Update",
        message: "Deseja salvar as alterações deste registro?",
        icon: "edit",
        color: "orange",
		    row: formData
      });
    }
  })()
}}
